import java.io.*;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String userInput = reader.readLine();

            // Escape user input before displaying it
            String safeUserInput = StringEscapeUtils.escapeHtml4(userInput);
            System.out.println("Hello, " + safeUserInput + "! Welcome to our website.");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
